import{c as n,Q as t,j as a,m as o}from"./chunks/framework.BPKcPtvA.js";const h=JSON.parse('{"title":"Running a sample LDK node","description":"","frontmatter":{},"headers":[],"relativePath":"running-a-sample-ldk-node.md","filePath":"running-a-sample-ldk-node.md","lastUpdated":1701653309000}'),s={name:"running-a-sample-ldk-node.md"};function r(l,e,i,d,c,p){return t(),a("div",null,[...e[0]||(e[0]=[o(`<h1 id="running-a-sample-ldk-node" tabindex="-1">Running a sample LDK node <a class="header-anchor" href="#running-a-sample-ldk-node" aria-label="Permalink to &quot;Running a sample LDK node&quot;">​</a></h1><p>Let&#39;s run our first LDK node. We&#39;ll ensure we have a compatible Rust toolchain installed, setup Polar to create a local Lightning network and then start running the node.</p><div class="tip custom-block"><p class="custom-block-title">Not recommended for production use!</p><p>This guide is a quick start to get you up and running with an LDK node. It serves as a playground and a foundation to build upon and is NOT recommended for production environments. LDK doesn&#39;t come with a pre-packaged node but gives you the tools to build a node from scratch!</p></div><h2 id="installing-rust" tabindex="-1">Installing Rust <a class="header-anchor" href="#installing-rust" aria-label="Permalink to &quot;Installing Rust&quot;">​</a></h2><p>If you already have a working installation of the latest Rust compiler, feel free to skip to the next section.</p><p>To install the latest version of Rust, we recommend using <code>rustup</code>. Install <code>rustup</code> by following the instructions on <a href="https://rustup.rs/" target="_blank" rel="noreferrer">its website</a>. Once <code>rustup</code> is installed, ensure the latest toolchain is installed by running the command:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes one-dark-pro one-dark-pro vp-code" tabindex="0"><code><span class="line"><span>rustup default stable</span></span></code></pre></div><h2 id="setup-polar" tabindex="-1">Setup Polar <a class="header-anchor" href="#setup-polar" aria-label="Permalink to &quot;Setup Polar&quot;">​</a></h2><p>Next, let&#39;s setup Polar, which was built to help Lightning Network application developers quickly spin up one or more networks locally on their computers in regtest mode.</p><p>Polar can be <a href="https://lightningpolar.com/" target="_blank" rel="noreferrer">downloaded</a> for MacOS, Linux, and Windows. The source code is hosted <a href="https://github.com/jamaljsr/polar/releases/" target="_blank" rel="noreferrer">on Github</a></p><p>Mac and Windows users will need to install <a href="https://www.docker.com/products/docker-desktop" target="_blank" rel="noreferrer">Docker Desktop</a> as a dependency before using Polar. Linux users will need to download both <a href="https://docs.docker.com/get-docker/" target="_blank" rel="noreferrer">Docker Server</a> and <a href="https://docs.docker.com/compose/install/" target="_blank" rel="noreferrer">Docker Compose</a>.</p><p>After downloading, installing, and running Polar, spin up a new cluster of LND, Core Lightning, eclair, and bitcoind nodes. This will create a Docker container within which Polar will operate.</p><p>Click the orange <strong>Create Network</strong> button and Polar should display a new interface.</p><p>Press the orange <strong>Start</strong> button in the top right corner to start your local network. It takes a couple seconds for the nodes to boot up, but the indicator lights will eventually turn green signaling that the process has completed.</p><h2 id="running-the-ldk-sample-node" tabindex="-1">Running the LDK Sample Node <a class="header-anchor" href="#running-the-ldk-sample-node" aria-label="Permalink to &quot;Running the LDK Sample Node&quot;">​</a></h2><p>Start by cloning the LDK sample node from Github and changing into the new directory</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes one-dark-pro one-dark-pro vp-code" tabindex="0"><code><span class="line"><span>git clone https://github.com/lightningdevkit/ldk-sample</span></span>
<span class="line"><span>cd ldk-sample</span></span></code></pre></div><p>Now, run the following command:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes one-dark-pro one-dark-pro vp-code" tabindex="0"><code><span class="line"><span>cargo run polaruser:polarpass@127.0.0.1:18443 ./ 9732 regtest hellolightning 0.0.0.0:9732</span></span></code></pre></div><p>If you have a different setup that doesn&#39;t involve Polar you can modify this command so that it contains different credentials.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes one-dark-pro one-dark-pro vp-code" tabindex="0"><code><span class="line"><span>cargo run &lt;bitcoind-rpc-username&gt;:&lt;bitcoind-rpc-password&gt;@&lt;bitcoind-rpc-host&gt;:&lt;bitcoind-rpc-port&gt; &lt;ldk_storage_directory_path&gt; [&lt;ldk-peer-listening-port&gt;] [&lt;bitcoin-network&gt;] [&lt;announced-node-name&gt;] [&lt;announced-listen-addr&gt;]</span></span></code></pre></div><p><code>bitcoind</code>&#39;s RPC username and password likely can be found through <code>cat ~/.bitcoin/.cookie</code>.</p><p><code>bitcoin-network</code>: defaults to <code>testnet</code>. Options: <code>testnet</code>, <code>regtest</code>, and <code>signet</code>.</p><p><code>ldk-peer-listening-port</code>: defaults to 9735.</p><p><code>announced-node-name</code> and <code>announced-listen-addr</code> : default to nothing, disabling any public announcements of this node.</p><p><code>announced-node-name</code>: can be any string up to 32 bytes in length, representing this node&#39;s alias. <code>announced-listen-addr</code>: can be set to an IPv4 or IPv6 address to announce that as a publicly-connectable address for this node.</p><p>Your LDK node should now be in action!</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes one-dark-pro one-dark-pro vp-code" tabindex="0"><code><span class="line"><span>LDK startup successful. To view available commands: &quot;help&quot;.</span></span>
<span class="line"><span>LDK logs are available at &lt;your-supplied-ldk-data-dir-path&gt;/.ldk/logs</span></span>
<span class="line"><span>Local Node ID is 02e8788eb41ac1731352d87ced719afce91a1201cf0d6cca12ee79502db1b0e317.</span></span></code></pre></div><p>If you want to connect to another node you created with Polar select the node there. In the <strong>Connect</strong> tab you can copy the <code>P2P External</code> connection info. Running <code>connectpeer</code> with that will get you connected.</p><p>To check out the complete reference for constructing a Lightning node with LDK check out the <a href="https://github.com/lightningdevkit/ldk-sample" target="_blank" rel="noreferrer">Github repo</a></p>`,30)])])}const g=n(s,[["render",r]]);export{h as __pageData,g as default};
